// sendEmail.js
const nodemailer = require('nodemailer');
require('dotenv').config(); // For loading environment variables (optional)

// Check if recipient email is provided as argument
const args = process.argv.slice(2);
if (args.length === 0) {
    console.error('Please provide a recipient email address as an argument');
    console.log('Usage: node sendEmail.js recipient@example.com');
    process.exit(1);
}

const recipientEmail = args[0];

// Validate email format (basic validation)
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRegex.test(recipientEmail)) {
    console.error('Please provide a valid email address');
    process.exit(1);
}

