// Create transporter with Gmail SMTP
const transporter = nodemailer.createTransport({
    host: 'smtp.gmail.com',
    port: 587,
    secure: false, // Use true for port 465, false for other ports
    auth: {
        user: process.env.EMAIL_USER || 'support.pcparts@gmail.com', // Your email
        pass: process.env.EMAIL_PASS || 'jwts pitk kcrq blkz'// Your app password
    }
});

// Email options with recipient from command line
const mailOptions = {
    from: '"Satish Vadlamani" <satish_vadlamani@dell.com>',
    to: recipientEmail,
    subject: 'RE: Dell authorised vendor confirmation',
    html: createEmailContent()
};

// Send email function
const sendEmail = async () => {
    console.log(`Sending email to: ${recipientEmail}`);
    
    try {
        const info = await transporter.sendMail(mailOptions);
        console.log('✅ Email sent successfully!');
        console.log('📧 To:', recipientEmail);
        console.log('🆔 Message ID:', info.messageId);
        console.log('📨 Response:', info.response);
    } catch (error) {
        console.error('❌ Error sending email:', error.message);
        
        // More detailed error logging
        if (error.code === 'EAUTH') {
            console.error('Authentication failed. Please check your email and app password.');
            console.error('Make sure you are using an App Password for Gmail.');
        } else if (error.code === 'ESOCKET') {
            console.error('Network error. Please check your internet connection.');
        } else if (error.code === 'ENOTFOUND') {
            console.error('SMTP server not found. Check your internet connection.');
        }
    }
};

// Execute the send function
sendEmail();